import React from 'react';

const Hero = () => (
    <section style={{ padding: '100px 20px', textAlign: 'center', background: '#080402', color: '#fff' }}>
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
            <span style={{ color: '#ea580c', fontWeight: 'bold', textTransform: 'uppercase' }}>Portal Loker No. 1 di Solo</span>
            <h1 style={{ fontSize: '4rem', margin: '20px 0', lineHeight: '1.1' }}>Mastering Your <br/> <span style={{ color: '#ea580c' }}>Career Needs.</span></h1>
            <p style={{ color: '#a3a3a3', fontSize: '1.2rem', marginBottom: '40px' }}>Temukan lowongan kerja terbaik yang sesuai dengan skill dan passion Anda di wilayah Solo dan sekitarnya.</p>
            <div style={{ display: 'flex', gap: '20px', justifyContent: 'center' }}>
                <button style={{ padding: '15px 30px', background: '#ea580c', border: 'none', borderRadius: '10px', color: '#fff', fontWeight: 'bold' }}>Mulai Eksplorasi</button>
            </div>
        </div>
    </section>
);
export default Hero;
